230→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
231→  const area = polygonArea(points);
232→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
233→  return {
234→    id: generateId('room'),
235→    name,
236→    points: points.map(p => ({ x: p.x, y: p.y })),
237→    labelPosition: { ...centroid },
238→    color,
239→    area,
240→  };
241→}
